const srcSel=$('#fn-src'), tgtSel=$('#fn-tgt'), rand=$('#fn-rand');
const assignRow=$('#fn-assign'), svg=$('#fn-svg'), out=$('#fn-out');
let nS=2, nT=2, assign=[0,1];
const SRC_LABELS = ['a','b','c'];

function ensureAssignLength(){
  while(assign.length < nS) assign.push(0);
  assign = assign.slice(0,nS).map(v=>Math.min(v,nT-1));
}
function buildAssignUI(){
  assignRow.innerHTML='';
  const lab = document.createElement('span');
  lab.className='small'; lab.style.color='var(--mute)';
  lab.textContent='function: ';
  assignRow.appendChild(lab);
  for(let i=0;i<nS;i++){
    const block=document.createElement('span');
    block.innerHTML = `<span class="small" style="color:var(--mute)">${SRC_LABELS[i]} ↦ </span>`;
    const sel=document.createElement('select');
    sel.style.marginLeft='.2rem'; sel.style.marginRight='.6rem';
    for(let j=0;j<nT;j++){
      const o=document.createElement('option'); o.value=j; o.textContent=String(j+1);
      if(assign[i]===j) o.selected=true;
      sel.appendChild(o);
    }
    sel.addEventListener('change',()=>{assign[i]=parseInt(sel.value,10); render();});
    block.appendChild(sel);
    assignRow.appendChild(block);
  }
}
function render(){
  svg.innerHTML='';
  const W=620, H=260;
  const xL=170, xR=450;
  const yMidS=H/2, yMidT=H/2;
  const spacing=52;
  // source blob
  const srcYs=[]; const tgtYs=[];
  for(let i=0;i<nS;i++) srcYs.push(yMidS + (i - (nS-1)/2)*spacing);
  for(let j=0;j<nT;j++) tgtYs.push(yMidT + (j - (nT-1)/2)*spacing);
  // blob rectangles
  svg.appendChild(SVG('rect',{x:xL-60,y:Math.min(...srcYs)-34,width:120,
    height:(srcYs[srcYs.length-1]-srcYs[0])+68,rx:16,ry:16,
    fill:'rgba(88,196,221,0.08)',stroke:'var(--blue)','stroke-dasharray':'4 4'}));
  svg.appendChild(SVG('rect',{x:xR-60,y:Math.min(...tgtYs)-34,width:120,
    height:(tgtYs[tgtYs.length-1]-tgtYs[0])+68,rx:16,ry:16,
    fill:'rgba(255,216,102,0.08)',stroke:'var(--yellow)','stroke-dasharray':'4 4'}));
  // labels
  const tS=SVG('text',{x:xL,y:Math.min(...srcYs)-46,'text-anchor':'middle','font-size':13,fill:'var(--blue)'});
  tS.textContent='F(0) — source set'; svg.appendChild(tS);
  const tT=SVG('text',{x:xR,y:Math.min(...tgtYs)-46,'text-anchor':'middle','font-size':13,fill:'var(--yellow)'});
  tT.textContent='F(1) — target set'; svg.appendChild(tT);
  // dots + labels
  for(let i=0;i<nS;i++){
    svg.appendChild(SVG('circle',{cx:xL,cy:srcYs[i],r:7,fill:'var(--blue)'}));
    const t=SVG('text',{x:xL-18,y:srcYs[i]+5,'text-anchor':'end','font-size':13,fill:'#fff'});
    t.textContent=SRC_LABELS[i]; svg.appendChild(t);
  }
  for(let j=0;j<nT;j++){
    svg.appendChild(SVG('circle',{cx:xR,cy:tgtYs[j],r:7,fill:'var(--yellow)'}));
    const t=SVG('text',{x:xR+18,y:tgtYs[j]+5,'text-anchor':'start','font-size':13,fill:'#fff'});
    t.textContent=String(j+1); svg.appendChild(t);
  }
  // arrows
  ensureArrow(svg,'fn-arr','var(--violet)');
  for(let i=0;i<nS;i++){
    const j=assign[i];
    const path=SVG('path',{d:`M${xL+10} ${srcYs[i]} C ${xL+120} ${srcYs[i]}, ${xR-120} ${tgtYs[j]}, ${xR-10} ${tgtYs[j]}`,
      fill:'none',stroke:'var(--violet)','stroke-width':1.6,'marker-end':'url(#fn-arr)'});
    svg.appendChild(path);
  }
  // image
  const image = [...new Set(assign)].sort((a,b)=>a-b);
  const injective = (new Set(assign).size === assign.length);
  const surjective = image.length === nT;
  let msg = `F(0) = {${SRC_LABELS.slice(0,nS).join(',')}}   (size ${nS})\n`
          + `F(1) = {${Array.from({length:nT},(_,j)=>j+1).join(',')}}   (size ${nT})\n`
          + `F(0→1) : ${SRC_LABELS.slice(0,nS).map((x,i)=>`${x}↦${assign[i]+1}`).join(', ')}\n`
          + `image = {${image.map(j=>j+1).join(',')}}   (size ${image.length})\n`
          + `injective? ${injective?'yes':'no'}   surjective? ${surjective?'yes':'no'}`;
  out.textContent = msg;
}
function rebuild(){
  nS=parseInt(srcSel.value,10); nT=parseInt(tgtSel.value,10);
  ensureAssignLength(); buildAssignUI(); render();
}
srcSel.addEventListener('change',rebuild);
tgtSel.addEventListener('change',rebuild);
rand.addEventListener('click',()=>{
  assign = Array.from({length:nS},()=>Math.floor(Math.random()*nT));
  buildAssignUI(); render();
});
rebuild();

