params.scriptBodyLiteral:
(function(){
  // Poset category: 0 < 1 < 2 (⊥, M, ⊤). Hom(i,j) = singleton if i<=j else empty.
  // Work in Set-valued CONTRAVARIANT functors. h_X(C) = Hom(C,X) — a singleton if C<=X else empty.
  // We display F by giving, for each object, a small natural number |F(obj)| and a chosen restriction map (contravariant).
  // A contravariant functor F on {0<1<2} is: sets F(0),F(1),F(2) + maps F(2)->F(1), F(1)->F(0). (Functoriality is automatic.)
  // Then Nat(h_X, F) ≅ F(X). We enumerate both and display.

  const OBJS = ['⊥','M','⊤']; // indexed 0,1,2
  const N=3;
  const yoX=$('#yo-X'), svg=$('#yo-svg'), out=$('#yo-out'), reroll=$('#yo-reroll');

  // F: store as sets (arrays of labels) + restriction maps.
  let F = randomF();

  function randomF(){
    const sizes = [1+Math.floor(Math.random()*3), 1+Math.floor(Math.random()*3), 1+Math.floor(Math.random()*3)];
    const mk = (n,prefix) => Array.from({length:n},(_,i)=>`${prefix}${i+1}`);
    const sets = [mk(sizes[0],'p'), mk(sizes[1],'q'), mk(sizes[2],'r')];
    // restriction maps rho_{i+1->i}: F(i+1) -> F(i)
    // i.e. rho10: sets[1] -> sets[0], rho21: sets[2] -> sets[1]
    const rho10 = sets[1].map(()=>Math.floor(Math.random()*sizes[0]));
    const rho21 = sets[2].map(()=>Math.floor(Math.random()*sizes[1]));
    return {sets, rho10, rho21};
  }
  function hX_at(C, X){
    // Hom(C,X) is singleton if C<=X else empty
    return (C<=X) ? ['•'] : [];
  }
  function natTransToF(X, x_index){
    // given chosen element x = F(X)[x_index], the induced nat transformation's component at C
    // is the map Hom(C,X) -> F(C) sending the unique arrow to F(ι)(x) where ι: C->X is the unique map.
    // For our poset, F applied to ι: C->X (which only exists if C<=X) is a restriction F(X) -> F(C).
    // We compose the restriction chain X -> X-1 -> ... -> C.
    const comps = [];
    for(let C=0;C<=2;C++){
      if(C<=X){
        // restrict x from X down to C
        let y = x_index;
        for(let k=X; k>C; k--){
          if(k===2) y = F.rho21[y];
          else if(k===1) y = F.rho10[y];
        }
        comps.push({C, from:'•', to: F.sets[C][y]});
      } else {
        comps.push({C, from:null, to:null});
      }
    }
    return comps;
  }

  function render(){
    const X=parseInt(yoX.value,10);
    svg.innerHTML='';
    // Layout: a column of poset objects on the left, a table on the right
    // Poset diagram
    const px=[90,90,90], py=[240,150,60];
    // edges
    drawArrow(svg,[px[1],py[1]],[px[0],py[0]],{color:'var(--line)',markerId:'yo-arr-l',pad1:14,pad2:14,curve:0,width:1});
    drawArrow(svg,[px[2],py[2]],[px[1],py[1]],{color:'var(--line)',markerId:'yo-arr-l2',pad1:14,pad2:14,curve:0,width:1});
    for(let i=0;i<3;i++){
      const fill = (i===X)?'var(--yellow)':'var(--panel2)';
      const stroke = (i===X)?'var(--yellow)':'var(--blue)';
      drawNode(svg, px[i], py[i], OBJS[i], {r:18, fill, stroke, textColor:(i===X?'#111':'#fff')});
    }
    const pt=SVG('text',{x:90,y:30,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
    pt.textContent='poset 𝒞'; svg.appendChild(pt);

    // Table header
    const xs=[200,310,420,530];
    const tHead=['C','h_X(C)','F(C)','η_C : h_X(C)→F(C)'];
    tHead.forEach((h,i)=>{
      const t=SVG('text',{x:xs[i],y:34,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
      t.textContent=h; svg.appendChild(t);
    });
    // For each C display a row
    // Choose x ∈ F(X) for the demo: take first element.
    const x_idx = 0;
    const comps = natTransToF(X, x_idx);
    for(let C=0;C<3;C++){
      const y = 70 + C*70;
      // object
      const t0=SVG('text',{x:xs[0],y:y+4,'text-anchor':'middle','font-size':14,fill:'#fff'});
      t0.textContent=OBJS[C]; svg.appendChild(t0);
      // h_X(C)
      const h = hX_at(C,X);
      const t1=SVG('text',{x:xs[1],y:y+4,'text-anchor':'middle','font-size':13,fill:'var(--blue)','font-family':'ui-monospace, monospace'});
      t1.textContent = h.length? '{•}' : '∅';
      svg.appendChild(t1);
      // F(C)
      const t2=SVG('text',{x:xs[2],y:y+4,'text-anchor':'middle','font-size':13,fill:'var(--yellow)','font-family':'ui-monospace, monospace'});
      t2.textContent = '{'+F.sets[C].join(',')+'}';
      svg.appendChild(t2);
      // η_C
      const t3=SVG('text',{x:xs[3],y:y+4,'text-anchor':'middle','font-size':12,fill:'var(--ink)','font-family':'ui-monospace, monospace'});
      t3.textContent = (comps[C].to===null) ? '(trivially ∅→F(C))'
                      : `•  ↦  ${comps[C].to}`;
      svg.appendChild(t3);
    }

    // readout
    const FX = F.sets[X];
    let msg = `choosing X = ${OBJS[X]}.\n`;
    msg += `F(⊥)={${F.sets[0].join(',')}}, F(M)={${F.sets[1].join(',')}}, F(⊤)={${F.sets[2].join(',')}}\n`;
    msg += `restriction F(M)→F(⊥): ${F.rho10.map((v,i)=>`${F.sets[1][i]}↦${F.sets[0][v]}`).join(', ')}\n`;
    msg += `restriction F(⊤)→F(M): ${F.rho21.map((v,i)=>`${F.sets[2][i]}↦${F.sets[1][v]}`).join(', ')}\n\n`;
    msg += `Yoneda:   Nat(h_${OBJS[X]}, F)   ≅   F(${OBJS[X]}) = {${FX.join(',')}}\n`;
    msg += `so there are exactly ${FX.length} natural transformations h_${OBJS[X]} ⇒ F.\n\n`;
    msg += `the one with η_${OBJS[X]}(id) = ${FX[0]} acts on each component as shown above.`;
    out.textContent = msg;
  }
  yoX.addEventListener('change',render);
  reroll.addEventListener('click',()=>{F=randomF(); render();});
  render();
})();

