const presetSel=$('#pb-preset'), nXIn=$('#pb-nX'), nYIn=$('#pb-nY'), nZIn=$('#pb-nZ');
const apply=$('#pb-apply'), frow=$('#pb-frow'), grow=$('#pb-grow');
const svg=$('#pb-svg'), out=$('#pb-out');
let nX=3,nY=3,nZ=2;
let f=[0,0,1], g=[0,1,1];

function xLab(i){ return 'x'+(i+1); }
function yLab(i){ return 'y'+(i+1); }
function zLab(i){ return 'z'+(i+1); }

function presets(key){
  if(key==='classic'){ nX=3;nY=3;nZ=2; f=[0,0,1]; g=[0,1,1]; }
  else if(key==='fiber'){ nX=4;nY=1;nZ=3; f=[0,1,2,0]; g=[0]; }
  else if(key==='square'){ nX=3;nY=3;nZ=4; f=[0,1,2]; g=[1,2,3]; }
  else if(key==='constant'){ nX=3;nY=4;nZ=2; f=[0,1,1]; g=[0,0,0,0]; }
  else return; // custom: don't touch
}
function fitFG(){
  while(f.length<nX) f.push(0);
  while(g.length<nY) g.push(0);
  f=f.slice(0,nX).map(v=>Math.min(v,nZ-1));
  g=g.slice(0,nY).map(v=>Math.min(v,nZ-1));
}
function buildFGUI(){
  frow.innerHTML=''; grow.innerHTML='';
  const flab=document.createElement('span'); flab.className='small'; flab.style.color='var(--mute)';
  flab.textContent='f : X → Z  '; frow.appendChild(flab);
  for(let i=0;i<nX;i++){
    const b=document.createElement('span');
    b.innerHTML=`<span class="small" style="color:var(--mute)">${xLab(i)}↦</span>`;
    const s=document.createElement('select'); s.style.marginRight='.5rem';
    for(let j=0;j<nZ;j++){
      const o=document.createElement('option'); o.value=j; o.textContent=zLab(j);
      if(f[i]===j) o.selected=true;
      s.appendChild(o);
    }
    s.addEventListener('change',()=>{f[i]=parseInt(s.value,10); render();});
    b.appendChild(s); frow.appendChild(b);
  }
  const glab=document.createElement('span'); glab.className='small'; glab.style.color='var(--mute)';
  glab.textContent='g : Y → Z  '; grow.appendChild(glab);
  for(let i=0;i<nY;i++){
    const b=document.createElement('span');
    b.innerHTML=`<span class="small" style="color:var(--mute)">${yLab(i)}↦</span>`;
    const s=document.createElement('select'); s.style.marginRight='.5rem';
    for(let j=0;j<nZ;j++){
      const o=document.createElement('option'); o.value=j; o.textContent=zLab(j);
      if(g[i]===j) o.selected=true;
      s.appendChild(o);
    }
    s.addEventListener('change',()=>{g[i]=parseInt(s.value,10); render();});
    b.appendChild(s); grow.appendChild(b);
  }
}
function render(){
  svg.innerHTML='';
  // Compute pullback elements
  const PB=[]; // list of [i,j]
  for(let i=0;i<nX;i++) for(let j=0;j<nY;j++) if(f[i]===g[j]) PB.push([i,j]);

  const W=620, H=380;
  // positions for the four corners of the pullback square:
  // XZ_Y (PB) top-left, X top-right, Y bottom-left, Z bottom-right
  const PBpos=[170,90], Xpos=[450,90], Ypos=[170,290], Zpos=[450,290];
  const dotR=6;

  function blob(center, items, labeler, color, fill){
    const n = items.length;
    const spacing=32;
    const yTop = center[1] - (n-1)*spacing/2 - 24;
    const yBot = center[1] + (n-1)*spacing/2 + 24;
    svg.appendChild(SVG('rect',{x:center[0]-62,y:yTop,width:124,height:yBot-yTop,rx:14,ry:14,
      fill, stroke:color, 'stroke-dasharray':'4 4'}));
    const positions=[];
    for(let i=0;i<n;i++){
      const y = center[1] + (i - (n-1)/2)*spacing;
      svg.appendChild(SVG('circle',{cx:center[0],cy:y,r:dotR,fill:color}));
      const t=SVG('text',{x:center[0],y:y+4,'text-anchor':'middle','font-size':11,fill:'#111','font-weight':600});
      t.textContent=labeler(items[i]);
      svg.appendChild(t);
      positions.push([center[0],y]);
    }
    return positions;
  }

  // Draw blobs
  const Xitems = Array.from({length:nX},(_,i)=>i);
  const Yitems = Array.from({length:nY},(_,i)=>i);
  const Zitems = Array.from({length:nZ},(_,i)=>i);
  const PBitems = PB;
  const Xpts = blob(Xpos, Xitems, xLab, 'var(--blue)',  'rgba(88,196,221,0.08)');
  const Ypts = blob(Ypos, Yitems, yLab, 'var(--pink)',  'rgba(224,122,95,0.08)');
  const Zpts = blob(Zpos, Zitems, zLab, 'var(--yellow)','rgba(255,216,102,0.08)');
  const PBpts = blob(PBpos, PBitems, p=>`(${xLab(p[0])},${yLab(p[1])})`,
    PB.length? 'var(--green)' : 'var(--mute)',
    PB.length?'rgba(131,193,103,0.08)':'rgba(154,164,178,0.06)');

  // corner labels
  const lab = (p, text, col, dx=0, dy=-4) => {
    const t=SVG('text',{x:p[0]+dx,y:p[1]+dy,'font-size':14,fill:col,'text-anchor':'middle','font-weight':600});
    t.textContent=text; svg.appendChild(t);
  };
  lab(PBpos,'X ×_Z Y','var(--green)',0,-((PB.length-1)*32/2+44));
  lab(Xpos,'X','var(--blue)',0,-((nX-1)*32/2+44));
  lab(Ypos,'Y','var(--pink)',0,-((nY-1)*32/2+44));
  lab(Zpos,'Z','var(--yellow)',0,-((nZ-1)*32/2+44));

  // Arrows f, g
  ensureArrow(svg,'pb-arr','var(--blue)');
  ensureArrow(svg,'pb-arr2','var(--pink)');
  // f: for each x_i, Xpts[i] -> Zpts[f[i]]
  for(let i=0;i<nX;i++){
    const p1=Xpts[i], p2=Zpts[f[i]];
    svg.appendChild(SVG('line',{x1:p1[0]+10,y1:p1[1],x2:p2[0]+10,y2:p2[1],
      stroke:'var(--blue)','stroke-width':1.3,opacity:0.55,'marker-end':'url(#pb-arr)'}));
  }
  for(let j=0;j<nY;j++){
    const p1=Ypts[j], p2=Zpts[g[j]];
    svg.appendChild(SVG('line',{x1:p1[0]+10,y1:p1[1],x2:p2[0]+10,y2:p2[1],
      stroke:'var(--pink)','stroke-width':1.3,opacity:0.55,'marker-end':'url(#pb-arr2)'}));
  }
  // f and g labels (big)
  const fl=SVG('text',{x:(Xpos[0]+Zpos[0])/2 + 30, y:(Xpos[1]+Zpos[1])/2,'text-anchor':'middle','font-size':14,
    fill:'var(--blue)','font-style':'italic'});
  fl.textContent='f'; svg.appendChild(fl);
  const gl=SVG('text',{x:(Ypos[0]+Zpos[0])/2, y:(Ypos[1]+Zpos[1])/2 + 18,'text-anchor':'middle','font-size':14,
    fill:'var(--pink)','font-style':'italic'});
  gl.textContent='g'; svg.appendChild(gl);

  // Projections pr_X, pr_Y
  ensureArrow(svg,'pb-arr-prx','var(--green)');
  ensureArrow(svg,'pb-arr-pry','var(--green)');
  for(let k=0;k<PB.length;k++){
    const [i,j] = PB[k];
    const p = PBpts[k];
    svg.appendChild(SVG('line',{x1:p[0]+12,y1:p[1],x2:Xpts[i][0]-12,y2:Xpts[i][1],
      stroke:'var(--green)','stroke-width':1.2,opacity:0.7,'marker-end':'url(#pb-arr-prx)'}));
    svg.appendChild(SVG('line',{x1:p[0],y1:p[1]+12,x2:Ypts[j][0],y2:Ypts[j][1]-12,
      stroke:'var(--green)','stroke-width':1.2,opacity:0.7,'marker-end':'url(#pb-arr-pry)'}));
  }

  // commuting-square indicator
  const ok = SVG('text',{x:(PBpos[0]+Zpos[0])/2,y:(PBpos[1]+Zpos[1])/2,'text-anchor':'middle','font-size':11,
    fill:'var(--mute)','font-style':'italic'});
  ok.textContent='(square commutes by construction)';
  svg.appendChild(ok);

  // readout
  let msg = `|X|=${nX}, |Y|=${nY}, |Z|=${nZ}\n`;
  msg += `f: ${Array.from({length:nX},(_,i)=>`${xLab(i)}↦${zLab(f[i])}`).join(', ')}\n`;
  msg += `g: ${Array.from({length:nY},(_,j)=>`${yLab(j)}↦${zLab(g[j])}`).join(', ')}\n\n`;
  msg += `X ×_Z Y = {(x,y) : f(x)=g(y)}\n`;
  if(PB.length===0) msg += `        = ∅   (no agreement — pullback is empty)\n`;
  else {
    msg += '        = { ' + PB.map(([i,j])=>`(${xLab(i)},${yLab(j)})`).join(', ') + ' }\n';
    msg += `  (size ${PB.length})\n`;
  }
  // also show fibers over each z
  msg += '\nfibers, as a sanity check:\n';
  for(let z=0;z<nZ;z++){
    const Xz = Array.from({length:nX},(_,i)=>i).filter(i=>f[i]===z);
    const Yz = Array.from({length:nY},(_,j)=>j).filter(j=>g[j]===z);
    const fiberSize = Xz.length*Yz.length;
    msg += `  over ${zLab(z)}:  f⁻¹=${Xz.length?Xz.map(xLab).join(','):'∅'}   g⁻¹=${Yz.length?Yz.map(yLab).join(','):'∅'}   contributes ${fiberSize} pairs\n`;
  }
  msg += `\nand indeed  |X ×_Z Y|  =  Σ_z  |f⁻¹(z)|·|g⁻¹(z)|`;
  out.textContent = msg;
}

