const GROUPS = {
  Z2:  (()=>{ return {name:'ℤ/2', els:[0,1], mult:(a,b)=>(a+b)%2, inv:a=>(2-a)%2, id:0, fmt:a=>String(a), gens:[1]}})(),
  Z3:  (()=>{ return {name:'ℤ/3', els:[0,1,2], mult:(a,b)=>(a+b)%3, inv:a=>(3-a)%3, id:0, fmt:a=>String(a), gens:[1,2]}})(),
  Z:   (()=>{ return {name:'ℤ', els:null, mult:(a,b)=>a+b, inv:a=>-a, id:0, fmt:a=>String(a), gens:[0,1,-1,2,-2,3]}})(),
  S3:  (()=>{
    // elements as permutations of [0,1,2]
    const e=[0,1,2], r1=[1,2,0], r2=[2,0,1], s0=[0,2,1], s1=[2,1,0], s2=[1,0,2];
    const els=[e,r1,r2,s0,s1,s2];
    const names=['e','(123)','(132)','(23)','(13)','(12)'];
    function mult(a,b){ return a.map((_,i)=>a[b[i]]); }
    function inv(a){ const r=Array(a.length); a.forEach((v,i)=>r[v]=i); return r; }
    function find(p){ return els.findIndex(e=>e.every((v,i)=>v===p[i])); }
    return {name:'S₃', els, mult, inv, id:e, fmt:p=>names[find(p)], gens:[r1,s0], _names:names, _find:find};
  })(),
  Z2Z2:(()=>{
    const els=[[0,0],[1,0],[0,1],[1,1]];
    function mult(a,b){return [(a[0]+b[0])%2,(a[1]+b[1])%2]}
    function inv(a){return [(2-a[0])%2,(2-a[1])%2]}
    return {name:'ℤ/2 × ℤ/2', els, mult, inv, id:[0,0], fmt:a=>`(${a[0]},${a[1]})`, gens:[[1,0],[0,1]]};
  })(),
};
function groupEq(G,a,b){
  if(G.els===null) return a===b;
  if(Array.isArray(a)) return a.every((v,i)=>v===b[i]);
  return a===b;
}

let n=2, Gkey='Z';
let assign=[]; // for each generator, an element of G

function initAssign(){
  const G=GROUPS[Gkey];
  const pick = G.gens[0];
  assign = Array.from({length:n},(_,i)=>G.gens[i%G.gens.length]);
}
function buildAssignUI(){
  const G=GROUPS[Gkey];
  assignRow.innerHTML='';
  const lbl=document.createElement('span'); lbl.className='small'; lbl.style.color='var(--mute)';
  lbl.textContent=`f : X → U(${G.name})   `;
  assignRow.appendChild(lbl);
  for(let i=0;i<n;i++){
    const b=document.createElement('span');
    b.innerHTML=`<span class="small" style="color:var(--mute)">x${i+1}↦</span>`;
    const s=document.createElement('select'); s.style.marginLeft='.2rem'; s.style.marginRight='.5rem';
    const opts = G.els || G.gens; // Z is infinite; offer gens as palette
    for(let j=0;j<opts.length;j++){
      const v=opts[j];
      const o=document.createElement('option'); o.value=j; o.textContent=G.fmt(v);
      if(groupEq(G,v,assign[i])) o.selected=true;
      s.appendChild(o);
    }
    s.addEventListener('change',()=>{
      const idx=parseInt(s.value,10);
      assign[i]=opts[idx];
      render();
    });
    b.appendChild(s); assignRow.appendChild(b);
  }
}

// Enumerate reduced words of length <= L in generators x1..xn and their inverses.
// Letter codes: positive (1..n) for xi, negative (-1..-n) for xi^{-1}.
function reducedWords(n, maxLen){
  const out=[['']]; // store as arrays of codes; include empty word (identity)
  const byLen=[[[]]]; // length 0
  for(let L=1;L<=maxLen;L++){
    const prev=byLen[L-1]; const cur=[];
    for(const w of prev){
      const last = w.length? w[w.length-1] : null;
      for(let k=1;k<=n;k++){
        for(const sign of [1,-1]){
          const c = sign*k;
          if(last!==null && last===-c) continue; // no cancellation
          cur.push([...w, c]);
        }
      }
    }
    byLen.push(cur);
  }
  const all=[];
  for(const L of byLen) for(const w of L) all.push(w);
  return all;
}

function formatWord(w){
  if(w.length===0) return 'ε';
  const sup = {'-1':'⁻¹'};
  return w.map(c=>{
    const i = Math.abs(c);
    return 'x'+i + (c<0?'⁻¹':'');
  }).join(' ');
}
function evalExt(w, G, assign){
  let cur=G.id;
  for(const c of w){
    const gen = assign[Math.abs(c)-1];
    const factor = c<0 ? G.inv(gen) : gen;
    cur = G.mult(cur, factor);
  }
  return cur;
}

function render(){
  const G=GROUPS[Gkey];
  svg.innerHTML='';
  // Draw unit diagram: X -> U(F(X)) -> U(G)
  // Three "blobs" indicating X on the left, F(X) middle, G right, with η and tilde-f arrows
  ensureArrow(svg,'aj-arr1','var(--violet)');
  ensureArrow(svg,'aj-arr2','var(--yellow)');
  ensureArrow(svg,'aj-arr3','var(--green)');
  svg.appendChild(SVG('rect',{x:30,y:50,width:140,height:110,rx:14,ry:14,
    fill:'rgba(88,196,221,0.08)',stroke:'var(--blue)','stroke-dasharray':'4 4'}));
  svg.appendChild(SVG('rect',{x:230,y:30,width:180,height:150,rx:14,ry:14,
    fill:'rgba(179,157,219,0.08)',stroke:'var(--violet)','stroke-dasharray':'4 4'}));
  svg.appendChild(SVG('rect',{x:470,y:50,width:130,height:110,rx:14,ry:14,
    fill:'rgba(131,193,103,0.08)',stroke:'var(--green)','stroke-dasharray':'4 4'}));
  const lab=(x,y,t,c)=>{const e=SVG('text',{x,y,'text-anchor':'middle','font-size':13,fill:c,'font-weight':600});e.textContent=t;svg.appendChild(e)};
  lab(100,40,'X','var(--blue)');
  lab(320,20,'F(X) — free group','var(--violet)');
  lab(535,40,`U(${G.name})`,'var(--green)');
  // generators
  for(let i=0;i<n;i++){
    const y=80+i*24;
    svg.appendChild(SVG('circle',{cx:100,cy:y,r:5,fill:'var(--blue)'}));
    const t=SVG('text',{x:100,y:y+4,'text-anchor':'middle','font-size':10,fill:'#111','font-weight':700});
    t.textContent=`x${i+1}`; svg.appendChild(t);
    // unit
    drawArrow(svg,[100,y],[250,y],{color:'var(--violet)',markerId:'aj-arr1',label:null,pad1:10,pad2:0});
  }
  // η label
  const etaL=SVG('text',{x:185,y:60,'text-anchor':'middle','font-size':12,fill:'var(--violet)','font-style':'italic'});
  etaL.textContent='η_X  (unit)'; svg.appendChild(etaL);
  // sample words inside F(X)
  const shortWords = reducedWords(n, 2).slice(0,8);
  for(let k=0;k<shortWords.length;k++){
    const y = 60 + k*14;
    const t=SVG('text',{x:320,y,'text-anchor':'middle','font-size':11,fill:'var(--ink)','font-family':'ui-monospace, monospace'});
    t.textContent=formatWord(shortWords[k]); svg.appendChild(t);
  }
  // ~f arrow to G
  drawArrow(svg,[410,100],[475,100],{color:'var(--yellow)',markerId:'aj-arr2',label:'f̃ (universal extension)',labelSide:1,curve:-14,pad1:4,pad2:4});

  // list target images
  const Gimages = shortWords.map(w=>evalExt(w,G,assign));
  for(let k=0;k<Gimages.length;k++){
    const y = 60 + k*14;
    const t=SVG('text',{x:535,y,'text-anchor':'middle','font-size':11,fill:'var(--green)','font-family':'ui-monospace, monospace'});
    t.textContent=G.fmt(Gimages[k]); svg.appendChild(t);
  }

  // readout: enumerate longer words up to length 3
  const wordsAll = reducedWords(n, 3);
  let lines = [];
  lines.push(`X = {${Array.from({length:n},(_,i)=>'x'+(i+1)).join(',')}}`);
  lines.push(`G = ${G.name}`);
  lines.push(`f : X → U(G)`);
  for(let i=0;i<n;i++) lines.push(`    x${i+1} ↦ ${G.fmt(assign[i])}`);
  lines.push('');
  lines.push(`universal extension f̃ : F(X) → G on reduced words of length ≤ 3:`);
  lines.push('');
  for(const w of wordsAll){
    const img = evalExt(w,G,assign);
    lines.push(`  f̃(${formatWord(w).padEnd(18,' ')}) = ${G.fmt(img)}`);
  }
  lines.push('');
  lines.push(`the triangle  X ─η→ U(F(X)) ─U(f̃)→ U(G)  recovers f.`);
  out.textContent = lines.join('\n');
}

