      nodes: { A: {x: 280, y: 160} },
      intro: "Suppose e and e' are both identity morphisms on A. We'll show e = e'.",
      // arrows keyed by id
      given: [
        {id:'e',      from:'A', to:'A', loop:'top',    label:"e"},
        {id:'eprime', from:'A', to:'A', loop:'bottom', label:"e'"}
      ],
      steps: [
        {
          highlight:['e'],
          equation: "e ∘ e' = e'",
          text: "Since e is an identity on A, we have e ∘ g = g for every g ending at A. Take g = e'."
        },
        {
          highlight:['eprime'],
          equation: "e ∘ e' = e",
          text: "Since e' is an identity on A, we have f ∘ e' = f for every f starting at A. Take f = e."
        },
        {
          highlight:[],
          equation: "⟹   e = e'",
          text: "Both equations read off the same composite e ∘ e'. So the two morphisms we started with are literally equal.",
          done: true
        }
      ]
    },

    initial: {
      title: 'Initial objects are unique up to unique iso',
      nodes: { I: {x: 160, y: 160}, J: {x: 400, y: 160} },
      intro: "Suppose I and J are both initial in a category C — from each, there is a unique arrow to every object.",
      given: [],
      steps: [
        {
          add: [{id:'f', from:'I', to:'J', curve:-22, label:"f", derived:true}],
          highlight: ['f'],
          equation: "∃! f: I → J",
          text: "I is initial, so there is a unique arrow from I to any object — in particular, to J. Call it f."
        },
        {
          add: [{id:'g', from:'J', to:'I', curve:-22, label:"g", derived:true}],
          highlight: ['g'],
          equation: "∃! g: J → I",
          text: "Symmetrically, J is initial, so there is a unique arrow g: J → I."
        },
        {
          highlight: ['f','g'],
          equation: "g ∘ f = id_I",
          text: "Consider g ∘ f : I → I. But I is initial, so there is exactly ONE arrow I → I. The identity id_I is such an arrow — so it IS the unique one, and therefore g ∘ f = id_I."
        },
        {
          highlight: ['f','g'],
          equation: "f ∘ g = id_J",
          text: "The symmetric argument gives f ∘ g = id_J."
        },
        {
          highlight: ['f'],
          equation: "⟹  I ≅ J uniquely via f",
          text: "f and g are mutually inverse, so f is an iso. And it was the unique arrow from I to J, so the iso is unique too.",
          done: true
        }
      ]
    },

    product: {
      title: 'Products are unique up to unique iso',
      nodes: {
        P: {x: 130, y:  80},
        Q: {x: 430, y:  80},
        X: {x: 180, y: 260},
        Y: {x: 380, y: 260}
      },
      intro: "Suppose both P and Q are products of X and Y — each has projection arrows, and each satisfies the universal property.",
      given: [
        {id:'pi1',  from:'P', to:'X', label:'π₁'},
        {id:'pi2',  from:'P', to:'Y', label:'π₂'},
        {id:'rho1', from:'Q', to:'X', label:'ρ₁'},
        {id:'rho2', from:'Q', to:'Y', label:'ρ₂'}
      ],
      steps: [
        {
          add: [{id:'u', from:'P', to:'Q', curve:-30, label:"u", derived:true}],
          highlight: ['u'],
          equation: "∃! u: P → Q  with ρ₁u = π₁, ρ₂u = π₂",
          text: "P carries a cone (π₁, π₂) over {X, Y}. The universal property of Q says there is a UNIQUE arrow u: P → Q making ρ₁u = π₁ and ρ₂u = π₂."
        },
        {
          add: [{id:'v', from:'Q', to:'P', curve:-30, label:"v", derived:true}],
          highlight: ['v'],
          equation: "∃! v: Q → P  with π₁v = ρ₁, π₂v = ρ₂",
          text: "Symmetrically, Q carries a cone over {X, Y}. The universal property of P produces a unique v: Q → P."
        },
        {
          highlight: ['u','v'],
          equation: "π₁(vu) = π₁,   π₂(vu) = π₂",
          text: "Consider vu: P → P. Then π₁(vu) = (π₁v)u = ρ₁u = π₁, and similarly π₂(vu) = π₂. So vu is a self-map of P making the projections commute."
        },
        {
          highlight: ['u','v'],
          equation: "vu = id_P",
          text: "But id_P also makes the projections commute: π₁·id_P = π₁. The UNIQUENESS half of P's universal property forces vu = id_P."
        },
        {
          highlight: ['u','v'],
          equation: "uv = id_Q",
          text: "The symmetric argument gives uv = id_Q."
        },
        {
          highlight: ['u'],
          equation: "⟹  P ≅ Q uniquely",
          text: "u: P → Q is an iso with inverse v. And u was the unique arrow from P making the projections match, so the isomorphism is canonical — no choice was made.",
          done: true
        }
      ]
    }
  }

