{
    product: {
      X: 'A × B',
      functor: 'C  ↦  Hom(C,A) × Hom(C,B)',
      u: 'the pair of projections (π_A, π_B) ∈ Hom(A×B,A) × Hom(A×B,B)',
      factoring: 'given (f: C→A, g: C→B), the unique ⟨f,g⟩: C → A×B satisfies π_A∘⟨f,g⟩ = f and π_B∘⟨f,g⟩ = g'
    },
    coproduct: {
      X: 'A ⊔ B',
      functor: 'C  ↦  Hom(A,C) × Hom(B,C)',
      u: 'the pair of inclusions (ι_A, ι_B) ∈ Hom(A, A⊔B) × Hom(B, A⊔B)',
      factoring: 'given (f: A→C, g: B→C), the unique [f,g]: A⊔B → C satisfies [f,g]∘ι_A = f and [f,g]∘ι_B = g'
    },
    free: {
      X: 'F(S)  (free group on S)',
      functor: 'G  ↦  Hom_Set(S, U(G))',
      u: 'the inclusion η_S: S → U(F(S)) sending each generator to itself',
      factoring: 'each set-function f: S → U(G) extends to a unique group-hom F(S) → G — the free-forgetful adjunction'
    },
    tensor: {
      X: 'M ⊗_R N',
      functor: 'P  ↦  Bilin_R(M × N, P)',
      u: 'the canonical R-bilinear map ⊗: M × N → M⊗N, (m,n) ↦ m⊗n',
      factoring: 'every R-bilinear φ: M×N → P factors uniquely as φ = φ̃ ∘ ⊗ with φ̃: M⊗N → P R-linear'
    },
    abelian: {
      X: 'G^ab = G/[G,G]',
      functor: 'A  ↦  Hom_Grp(G, A)   (A abelian)',
      u: 'the quotient q: G → G^ab',
      factoring: 'every homomorphism G → A to an abelian group factors uniquely through q'
    }
  }

