params.scriptBodyLiteral:
/* =============================== Section 10 widget =============================== */
(function(){
  const selA=$('#yo2-A'), svg=$('#yo2-svg'), out=$('#yo2-out'), reroll=$('#yo2-reroll');
  if(!svg) return;
  const OBJS=['⊥','M','⊤'];
  let F = randomF();
  let Aidx = 1;
  let chosen = 0;

  function randomF(){
    const sizes = [1+Math.floor(Math.random()*3), 1+Math.floor(Math.random()*3), 1+Math.floor(Math.random()*3)];
    const sets = sizes.map((n,i)=> Array.from({length:n},(_,k)=> String.fromCharCode(97+i*3+k)));
    // restriction maps rho10: F(M)->F(⊥), rho21: F(⊤)->F(M).
    const rho10 = sets[1].map(()=> Math.floor(Math.random()*sizes[0]));
    const rho21 = sets[2].map(()=> Math.floor(Math.random()*sizes[1]));
    return { sets, rho10, rho21 };
  }
  // Given chosen x-index in F(Aidx), compute component at each C (if C<=A)
  function components(){
    const comps = [];
    for(let C=0;C<=2;C++){
      if(C<=Aidx){
        let y=chosen;
        for(let k=Aidx;k>C;k--){
          if(k===2) y=F.rho21[y];
          else if(k===1) y=F.rho10[y];
        }
        comps.push({C, value: F.sets[C][y], idx:y});
      } else comps.push({C, value:null, idx:null});
    }
    return comps;
  }
  function render(){
    Aidx = parseInt(selA.value,10);
    if(chosen>=F.sets[Aidx].length) chosen=0;
    svg.innerHTML='';
    // Left panel: F(A) with draggable dots
    const FA = F.sets[Aidx];
    const cx = 140, cy = 170;
    // panel rect
    svg.appendChild(SVG('rect',{x:50,y:60,width:180,height:220,rx:12,ry:12,
      fill:'rgba(255,216,102,0.06)',stroke:'var(--yellow)','stroke-dasharray':'4 4'}));
    const tTitle = SVG('text',{x:140,y:50,'text-anchor':'middle','font-size':13,
      fill:'var(--yellow)','font-weight':600});
    tTitle.textContent = `F(${OBJS[Aidx]}) — pick an element x`;
    svg.appendChild(tTitle);
    // dots
    const dots=[];
    for(let i=0;i<FA.length;i++){
      const y = 100 + i*36;
      const sel = (i===chosen);
      const r = SVG('circle',{cx:cx, cy:y, r: sel?12:8,
        fill: sel?'var(--yellow)':'var(--panel2)',
        stroke:'var(--yellow)','stroke-width':1.5,
        style:'cursor:pointer','data-i':i});
      svg.appendChild(r);
      const t = SVG('text',{x:cx, y:y+5,'text-anchor':'middle','font-size':12,
        fill:sel?'#0b0d10':'var(--ink)','font-weight': sel?700:500,
        'pointer-events':'none'});
      t.textContent = FA[i]; svg.appendChild(t);
      dots.push(r);
    }
    // Right panel: three rows for C=⊥,M,⊤ showing h_A(C) and η^x_C
    const xRight = 300;
    svg.appendChild(SVG('rect',{x:xRight-10,y:60,width:330,height:220,rx:12,ry:12,
      fill:'rgba(88,196,221,0.05)',stroke:'var(--blue)','stroke-dasharray':'4 4'}));
    const rT = SVG('text',{x:xRight+160,y:50,'text-anchor':'middle','font-size':13,
      fill:'var(--blue)','font-weight':600});
    rT.textContent = `natural transformation η^x : h_${OBJS[Aidx]} ⇒ F`;
    svg.appendChild(rT);
    const comps = components();
    for(let C=0;C<3;C++){
      const y = 95 + C*55;
      // row label
      const lab = SVG('text',{x:xRight, y:y+5,'font-size':13,fill:'var(--ink)','font-weight':600});
      lab.textContent = `C = ${OBJS[C]}:`;
      svg.appendChild(lab);
      // h_A(C)
      const hTxt = SVG('text',{x:xRight+70,y:y+5,'font-size':12,fill:'var(--mute)',
        'font-family':'ui-monospace, monospace'});
      hTxt.textContent = (C<=Aidx) ? 'h_A(C)={•}' : 'h_A(C)=∅';
      svg.appendChild(hTxt);
      // arrow
      if(C<=Aidx){
        const ar = SVG('text',{x:xRight+170,y:y+5,'font-size':14,fill:'var(--green)','font-family':'ui-monospace, monospace'});
        ar.textContent = `• ↦ ${comps[C].value}`;
        svg.appendChild(ar);
      } else {
        const ar = SVG('text',{x:xRight+170,y:y+5,'font-size':12,fill:'var(--mute)','font-style':'italic'});
        ar.textContent = '(trivially empty)';
        svg.appendChild(ar);
      }
    }
    // click handler on dots
    svg.addEventListener('click', onClick, {once:true});
    // readout
    let msg = `A = ${OBJS[Aidx]}\n`;
    msg += `F(⊥)={${F.sets[0].join(',')}}  F(M)={${F.sets[1].join(',')}}  F(⊤)={${F.sets[2].join(',')}}\n`;
    msg += `chosen x = ${FA[chosen]} ∈ F(${OBJS[Aidx]}).\n\n`;
    msg += `Yoneda: Nat(h_${OBJS[Aidx]}, F) ≅ F(${OBJS[Aidx]}). Under the bijection,\n`;
    msg += `x = ${FA[chosen]}  ↔  η^x with components:\n`;
    for(const c of comps){
      if(c.value===null) msg += `   η^x at ${OBJS[c.C]}: (vacuous, h_A is ∅)\n`;
      else msg += `   η^x at ${OBJS[c.C]}: • ↦ ${c.value}\n`;
    }
    out.textContent = msg;
  }
  function onClick(e){
    const i = e.target && e.target.getAttribute && e.target.getAttribute('data-i');
    if(i!=null){ chosen = parseInt(i,10); render(); }
    else render(); // re-bind handler
  }
  selA.addEventListener('change', ()=>{ chosen=0; render(); });
  reroll.addEventListener('click', ()=>{ F=randomF(); chosen=0; render(); });
  render();
})();

