params.bodyScript:
const nAIn=$('#po-nA'), nBIn=$('#po-nB'), nCIn=$('#po-nC');
const apply=$('#po-apply'), rand=$('#po-randomize');
const frow=$('#po-frow'), grow=$('#po-grow');
const svg=$('#po-svg'), out=$('#po-out');
if(!svg) return;
let nA=3,nB=3,nC=2, f=[0,1], g=[0,2];

function xLab(i,pref){ return pref+(i+1); }
function fit(){
  while(f.length<nC) f.push(0);
  while(g.length<nC) g.push(0);
  f = f.slice(0,nC).map(v=>Math.min(v,nA-1));
  g = g.slice(0,nC).map(v=>Math.min(v,nB-1));
}
function buildUI(){
  frow.innerHTML=''; grow.innerHTML='';
