    b.appendChild(s); frow.appendChild(b);
  }
  const gl=document.createElement('span'); gl.className='small'; gl.style.color='var(--mute)';
  gl.textContent='g : C → B  '; grow.appendChild(gl);
  for(let i=0;i<nC;i++){
