// Union-find on disjoint union A ⊔ B, where A-elements indexed 0..nA-1, B-elements indexed nA..nA+nB-1.
function computeQuotient(){
  const N = nA + nB;
  const parent = Array.from({length:N},(_,i)=>i);
  function find(x){ while(parent[x]!==x) x=parent[x]; return x; }
  function union(x,y){ const rx=find(x), ry=find(y); if(rx!==ry) parent[rx]=ry; }
  for(let i=0;i<nC;i++) union(f[i], nA + g[i]);
  // group by root
  const classes = {};
  for(let i=0;i<N;i++){
    const r = find(i);
    (classes[r] = classes[r] || []).push(i);
  }
  return Object.values(classes);
}
function render(){
