  msg += `classes (size ${classes.length}):\n`;
  for(const cl of classes){
    msg += '  { ' + cl.map(k=> k<nA? 'a'+(k+1):'b'+(k-nA+1)).join(', ') + ' }\n';
  }
  out.textContent = msg;
