/* =============================== Section 12 widget =============================== */
(function(){
  const nSl=$('#uc-nA'), nLbl=$('#uc-nA-lbl'), GSel=$('#uc-G'), svg=$('#uc-svg'), out=$('#uc-out');
  if(!svg) return;
  const GROUPS = {
    Z2: { name:'ℤ/2', n:2 },
    Z3: { name:'ℤ/3', n:3 },
    Z4: { name:'ℤ/4', n:4 }
  };
  function render(){
    const nA = parseInt(nSl.value,10); nLbl.textContent=String(nA);
    const Gkey = GSel.value, G = GROUPS[Gkey];
    svg.innerHTML='';

    // Three blobs: A (set), U(F(A)) = underlying set of free group, and G (target group as set)
    function blob(cx, cy, items, col, fill){
      const spacing=26, n=items.length;
      const yTop = cy - (n-1)*spacing/2 - 20;
      const yBot = cy + (n-1)*spacing/2 + 20;
      svg.appendChild(SVG('rect',{x:cx-60,y:yTop,width:120,height:yBot-yTop,rx:12,ry:12,
        fill:fill, stroke:col,'stroke-dasharray':'4 4'}));
      const pts=[];
      for(let i=0;i<n;i++){
        const y = cy + (i - (n-1)/2)*spacing;
        svg.appendChild(SVG('circle',{cx,cy:y,r:5,fill:col}));
        const t=SVG('text',{x:cx, y:y+4,'text-anchor':'middle','font-size':11,fill:'#111','font-weight':600});
        t.textContent = items[i]; svg.appendChild(t);
        pts.push([cx,y]);
      }
      return pts;
    }
    // Free group on A — we only display underlying set truncated to short reduced words
    function shortWords(n, maxLen){
      const res=[['ε']];
      let cur=[[]];
      for(let L=1;L<=maxLen;L++){
        const next=[];
        for(const w of cur){
          const last = w.length? w[w.length-1] : null;
          for(let k=1;k<=n;k++){
            for(const s of [1,-1]){
              const c=s*k;
              if(last!==null && last===-c) continue;
              next.push([...w,c]);
            }
          }
        }
        cur=next;
      }
      // format
      return ['ε', ...cur.map(w=>w.map(c=>'x'+Math.abs(c)+(c<0?'⁻¹':'')).join(''))];
    }

    const Aitems = Array.from({length:nA},(_,i)=>'x'+(i+1));
    const UFitems_full = shortWords(nA, 1); // just generators + their inverses + ε
    // keep small
    const UFitems = UFitems_full.slice(0, Math.min(UFitems_full.length, 6));
    const Gitems = Array.from({length:G.n},(_,i)=>String(i));

    const Apts = blob(110, 160, Aitems, 'var(--blue)',  'rgba(88,196,221,0.08)');
    const UFpts= blob(320, 160, UFitems,'var(--violet)','rgba(179,157,219,0.08)');
    const Gpts = blob(540, 160, Gitems, 'var(--green)', 'rgba(131,193,103,0.08)');

    // headers
    function hdr(cx, txt, col, y=60){
      const t=SVG('text',{x:cx, y,'text-anchor':'middle','font-size':13,fill:col,'font-weight':600});
      t.textContent=txt; svg.appendChild(t);
    }
    hdr(110,'A','var(--blue)');
    hdr(320,'U(F(A))','var(--violet)');
    hdr(540,`U(${G.name})`,'var(--green)');

    // unit η_A : A → U(F(A))  sends x_i to the one-letter word x_i
    ensureArrow(svg,'uc-eta','var(--yellow)');
    for(let i=0;i<nA;i++){
      const tgtIdx = UFitems.indexOf('x'+(i+1));
      if(tgtIdx>=0){
        drawArrow(svg, Apts[i], UFpts[tgtIdx], {color:'var(--yellow)', markerId:'uc-eta', pad1:10, pad2:10, width:1.4});
      }
    }
    hdr((110+320)/2, 'η_A : insert generators', 'var(--yellow)', 300);

    // pick a set-function f: A → U(G): take x_i ↦ i mod G.n
    const fVals = Apts.map((_,i)=> i % G.n);
    // extension tilde-f : U(F(A)) → U(G)
    function evalExt(word){
      if(word==='ε') return 0;
      let v=0;
      const toks=[];
      let i=0;
      while(i<word.length){
        if(word[i]==='x'){
          let j=i+1, num='';
          while(j<word.length && /\d/.test(word[j])){ num+=word[j]; j++; }
          let inv=false;
          if(word.substr(j,2)==='⁻¹'){ inv=true; j+=2; }
          const idx = parseInt(num,10)-1;
          const val = idx<nA ? fVals[idx] : 0;
          v = (v + (inv ? (G.n-val)%G.n : val)) % G.n;
          i=j;
        } else i++;
      }
      return v;
    }
    // counit ε_G : F(U(G)) → G is the evaluation of words. We don't draw F(U(G)), but we show ε on U(F(A)) via the composite ~f.
    ensureArrow(svg,'uc-ext','var(--pink)');
    for(let k=0;k<UFitems.length;k++){
      const target = evalExt(UFitems[k]);
      drawArrow(svg, UFpts[k], Gpts[target], {color:'var(--pink)', markerId:'uc-ext', pad1:8, pad2:8, width:1.1});
    }
    hdr((320+540)/2, 'f̃ (universal extension)', 'var(--pink)', 300);

    // readout
    let msg = `A = {${Aitems.join(',')}}   G = ${G.name}\n`;
    msg += `chosen f : A → U(G):   ${Aitems.map((a,i)=>`${a}↦${fVals[i]}`).join(', ')}\n\n`;
    msg += `Unit η_A : A → U(F(A))  sends each generator to its one-letter word.\n`;
    msg += `Universal extension f̃ : F(A) → G  satisfies  U(f̃) ∘ η_A = f  (triangle equation).\n\n`;
    msg += `check: U(f̃) ∘ η_A  at each a ∈ A:\n`;
    for(let i=0;i<nA;i++){
