const tSel=$('#kl-T'), frow=$('#kl-frow'), grow=$('#kl-grow'), svg=$('#kl-svg'), out=$('#kl-out');
if(!svg) return;
// Fix X = {x1,x2}, Y = {y1,y2}, Z = {z1,z2}
const X=['x₁','x₂'], Y=['y₁','y₂'], Z=['z₁','z₂'];
let f=[0,1], g=[0,1]; // for maybe: index into Y∪{⊥}; for list: small list encoded as integer code
// For Maybe: f: X → Y ⊔ ⊥, encode: 0..|Y|-1 → y_i, |Y| → ⊥
// For List: f: X → List(Y), we'll let f encode index into a small palette:
//   0: [], 1: [y1], 2: [y2], 3: [y1,y2], 4: [y2,y1], 5: [y1,y1]
const LIST_PALETTE_Y = [[],[0],[1],[0,1],[1,0],[0,0]];
const LIST_PALETTE_Z = [[],[0],[1],[0,1],[1,0],[0,0]];
function buildUI(){
  const mode=tSel.value;
  frow.innerHTML=''; grow.innerHTML='';
  const flbl=document.createElement('span'); flbl.className='small'; flbl.style.color='var(--mute)';
  flbl.textContent='f : X → T(Y)  '; frow.appendChild(flbl);
  for(let i=0;i<2;i++){
    const b=document.createElement('span');
    b.innerHTML=`<span class="small" style="color:var(--mute)">${X[i]}↦</span>`;
    const s=document.createElement('select'); s.style.marginRight='.5rem';
    if(mode==='maybe'){
      const opts=[...Y,'⊥'];
      for(let j=0;j<opts.length;j++){
        const o=document.createElement('option'); o.value=j; o.textContent=opts[j];
        if(f[i]===j) o.selected=true;
        s.appendChild(o);
      }
    } else {
      for(let j=0;j<LIST_PALETTE_Y.length;j++){
        const o=document.createElement('option'); o.value=j;
        o.textContent = '['+LIST_PALETTE_Y[j].map(k=>Y[k]).join(',')+']';
        if(f[i]===j) o.selected=true;
        s.appendChild(o);
      }
    }
    s.addEventListener('change',()=>{f[i]=parseInt(s.value,10); render();});
    b.appendChild(s); frow.appendChild(b);
  }
  const glbl=document.createElement('span'); glbl.className='small'; glbl.style.color='var(--mute)';
  glbl.textContent='g : Y → T(Z)  '; grow.appendChild(glbl);
  for(let i=0;i<2;i++){
    const b=document.createElement('span');
    b.innerHTML=`<span class="small" style="color:var(--mute)">${Y[i]}↦</span>`;
    const s=document.createElement('select'); s.style.marginRight='.5rem';
    if(mode==='maybe'){
      const opts=[...Z,'⊥'];
      for(let j=0;j<opts.length;j++){
        const o=document.createElement('option'); o.value=j; o.textContent=opts[j];
        if(g[i]===j) o.selected=true;
        s.appendChild(o);
      }
    } else {
      for(let j=0;j<LIST_PALETTE_Z.length;j++){
        const o=document.createElement('option'); o.value=j;
        o.textContent = '['+LIST_PALETTE_Z[j].map(k=>Z[k]).join(',')+']';
        if(g[i]===j) o.selected=true;
        s.appendChild(o);
      }
    }
    s.addEventListener('change',()=>{g[i]=parseInt(s.value,10); render();});
    b.appendChild(s); grow.appendChild(b);
  }
}
function render(){
  svg.innerHTML='';
  const mode=tSel.value;
  // three blobs X, Y, Z at y=90 or so
  function blob(cx,items,col,fill){
    const n=items.length, cy=140, spacing=38;
    const yTop = cy - (n-1)*spacing/2 - 22;
    svg.appendChild(SVG('rect',{x:cx-50,y:yTop,width:100,height:(n-1)*spacing+44,rx:12,ry:12,
      fill, stroke:col,'stroke-dasharray':'4 4'}));
    const pts=[];
    for(let i=0;i<n;i++){
      const y=cy + (i - (n-1)/2)*spacing;
      svg.appendChild(SVG('circle',{cx,cy:y,r:6,fill:col}));
      const t=SVG('text',{x:cx,y:y+4,'text-anchor':'middle','font-size':11,fill:'#111','font-weight':600});
      t.textContent=items[i]; svg.appendChild(t);
      pts.push([cx,y]);
    }
    const lab=SVG('text',{x:cx,y:yTop-10,'text-anchor':'middle','font-size':13,fill:col,'font-weight':600});
    lab.textContent = items[0].split('')[0].toUpperCase(); // X, Y, Z from first item
    svg.appendChild(lab);
    return pts;
  }
  const Xpts=blob(120,X,'var(--blue)','rgba(88,196,221,0.08)');
  const Ypts=blob(350,Y,'var(--pink)','rgba(224,122,95,0.08)');
  const Zpts=blob(560,Z,'var(--green)','rgba(131,193,103,0.08)');

  // Draw arrows for f: Xi to (Y_j or ⊥)
  ensureArrow(svg,'kl-f','var(--yellow)');
  ensureArrow(svg,'kl-g','var(--violet)');
  function drawKleisli(srcPts, tgtPts, mode, choices, color, markerId){
    for(let i=0;i<srcPts.length;i++){
      if(mode==='maybe'){
        const k = choices[i];
        if(k===tgtPts.length){
          // ⊥: draw a dangling X to nowhere
          const lb=SVG('text',{x:srcPts[i][0]+60,y:srcPts[i][1]+4,'font-size':12,fill:color,'font-weight':600});
          lb.textContent='↦ ⊥'; svg.appendChild(lb);
        } else {
          svg.appendChild(SVG('line',{x1:srcPts[i][0]+8,y1:srcPts[i][1],x2:tgtPts[k][0]-8,y2:tgtPts[k][1],
            stroke:color,'stroke-width':1.4,opacity:0.8,'marker-end':`url(#${markerId})`}));
        }
      } else {
        const list = (srcPts===Xpts?LIST_PALETTE_Y:LIST_PALETTE_Z)[choices[i]];
        for(const k of list){
          svg.appendChild(SVG('line',{x1:srcPts[i][0]+8,y1:srcPts[i][1],x2:tgtPts[k][0]-8,y2:tgtPts[k][1],
            stroke:color,'stroke-width':1.2,opacity:0.7,'marker-end':`url(#${markerId})`}));
        }
      }
    }
  }
  drawKleisli(Xpts,Ypts,mode,f,'var(--yellow)','kl-f');
  drawKleisli(Ypts,Zpts,mode,g,'var(--violet)','kl-g');

  // Compute composite g ∘_K f: X → T(Z)
  const composite = [];
  for(let i=0;i<X.length;i++){
    if(mode==='maybe'){
      if(f[i]===Y.length){ composite.push('⊥'); }
      else {
        const gOut = g[f[i]];
        composite.push(gOut===Z.length ? '⊥' : Z[gOut]);
      }
    } else {
      const ylist = LIST_PALETTE_Y[f[i]];
      let concat=[];
      for(const y of ylist){
        const gz = LIST_PALETTE_Z[g[y]];
        concat = concat.concat(gz);
      }
      composite.push('['+concat.map(k=>Z[k]).join(',')+']');
    }
  }
  // readout
  let msg = `monad T = ${mode==='maybe'?'Maybe':'List'}\n\n`;
  msg += `f : X → T(Y)\n`;
  for(let i=0;i<X.length;i++){
    if(mode==='maybe') msg += `   ${X[i]} ↦ ${f[i]===Y.length?'⊥':Y[f[i]]}\n`;
    else msg += `   ${X[i]} ↦ [${LIST_PALETTE_Y[f[i]].map(k=>Y[k]).join(',')}]\n`;
  }
  msg += `\ng : Y → T(Z)\n`;
  for(let i=0;i<Y.length;i++){
    if(mode==='maybe') msg += `   ${Y[i]} ↦ ${g[i]===Z.length?'⊥':Z[g[i]]}\n`;
    else msg += `   ${Y[i]} ↦ [${LIST_PALETTE_Z[g[i]].map(k=>Z[k]).join(',')}]\n`;
  }
  msg += `\nKleisli composite  g ∘_K f = μ ∘ T(g) ∘ f  : X → T(Z)\n`;
  for(let i=0;i<X.length;i++){
    msg += `   ${X[i]} ↦ ${composite[i]}\n`;
  }
  if(mode==='maybe'){
    msg += `\nNote: Maybe propagates ⊥. If f(x)=⊥ the composite is ⊥ without consulting g.`;
  } else {
    msg += `\nNote: List flattens (μ = concatenation). Length of composite = Σ |g(y)| over y in f(x).`;
  }
  out.textContent = msg;
}
tSel.addEventListener('change', ()=>{ f=[0,1]; g=[0,1]; buildUI(); render(); });
