  }
  msg += `\ng : Y → T(Z)\n`;
  for(let i=0;i<Y.length;i++){
    if(mode==='maybe') msg += `   ${Y[i]} ↦ ${g[i]===Z.length?'⊥':Z[g[i]]}\n`;
    else msg += `   ${Y[i]} ↦ [${LIST_PALETTE_Z[g[i]].map(k=>Z[k]).join(',')}]\n`;
  }
  msg += `\nKleisli composite  g ∘_K f = μ ∘ T(g) ∘ f  : X → T(Z)\n`;
  for(let i=0;i<X.length;i++){
    msg += `   ${X[i]} ↦ ${composite[i]}\n`;
  }
  if(mode==='maybe'){
    msg += `\nNote: Maybe propagates ⊥. If f(x)=⊥ the composite is ⊥ without consulting g.`;
  } else {
    msg += `\nNote: List flattens (μ = concatenation). Length of composite = Σ |g(y)| over y in f(x).`;
  }
  out.textContent = msg;
}
tSel.addEventListener('change', ()=>{ f=[0,1]; g=[0,1]; buildUI(); render(); });
buildUI(); render();

