/* =============================== Section 14 widget =============================== */
(function(){
  const modeSel=$('#kan-mode'), svg=$('#kan-svg'), out=$('#kan-out');
  if(!svg) return;
  // Scenario: A = {0,1} (discrete, 2 objects). B = {0,1,2} (poset: 0<1<2).
  // K: A→B sends 0↦0, 1↦2 (skipping middle).
  // F: A→Set assigns F(0)={p,q}, F(1)={r}.
  // Left Kan at b in B: colim over (K↓b).
  //   - b=0: (K↓0) contains only (0,id) → Lan(0)=F(0)={p,q}
  //   - b=1: (K↓1) contains (0,0→1). Lan(1)=F(0)={p,q} (colim over one-object diagram)
  //   - b=2: (K↓2) contains (0,0→2) and (1,1→2)=(1,id). Lan(2) = F(0) ⊔ F(1) = {p,q,r}
  // Right Kan at b: limit over (b↓K).
  //   - b=0: (0↓K) = {(0,0→0)=(0,id),(1,0→2)}. Ran(0) = F(0) × F(1) = 2*1 = 2 elements
  //   - b=1: (1↓K) = {(1,1→2)=(1,id)}. Ran(1)=F(1)={r}
  //   - b=2: (2↓K) = {(1,2→2)=(1,id)}. Ran(2)=F(1)={r}

  function render(){
    svg.innerHTML='';
    const mode = modeSel.value;

    // draw K: A → B on the left
    const yLine = 140;
    svg.appendChild(SVG('text',{x:30,y:yLine-60,'font-size':13,fill:'var(--mute)'}).appendChild(document.createTextNode('')) || SVG('text',{x:0,y:0}));
    const titleL = SVG('text',{x:30,y:yLine-70,'font-size':13,fill:'var(--mute)','font-weight':600});
    titleL.textContent='A  ─K→  B'; svg.appendChild(titleL);

    // A = 2 objects
    drawNode(svg, 60, yLine-30, '0', {r:14, stroke:'var(--blue)'});
    drawNode(svg, 60, yLine+30, '1', {r:14, stroke:'var(--blue)'});
    const aLbl=SVG('text',{x:30,y:yLine+5,'font-size':11,fill:'var(--mute)'}); aLbl.textContent='A'; svg.appendChild(aLbl);
    // B = 3 objects in a chain
    drawNode(svg, 200, yLine-60, '0', {r:14, stroke:'var(--yellow)'});
    drawNode(svg, 200, yLine, 'M', {r:14, stroke:'var(--yellow)'});
    drawNode(svg, 200, yLine+60, '2', {r:14, stroke:'var(--yellow)'});
    const bLbl=SVG('text',{x:170,y:yLine+5,'font-size':11,fill:'var(--mute)'}); bLbl.textContent='B'; svg.appendChild(bLbl);
    // B arrows (poset)
    drawArrow(svg,[200,yLine-46],[200,yLine-14],{color:'var(--line)',markerId:'kan-bp',pad1:6,pad2:6,width:1});
    drawArrow(svg,[200,yLine+14],[200,yLine+46],{color:'var(--line)',markerId:'kan-bp2',pad1:6,pad2:6,width:1});
    // K arrows
    drawArrow(svg,[60,yLine-30],[200,yLine-60],{color:'var(--violet)',markerId:'kan-k',pad1:14,pad2:14,width:1.4,label:'K'});
    drawArrow(svg,[60,yLine+30],[200,yLine+60],{color:'var(--violet)',markerId:'kan-k2',pad1:14,pad2:14,width:1.4});

    // F on A
    const Ftitle=SVG('text',{x:360,y:yLine-100,'font-size':13,fill:'var(--mute)','font-weight':600});
    Ftitle.textContent='F : A → Set'; svg.appendChild(Ftitle);
    const Fpts = [
      [360, yLine-40, '{p,q}'],
      [360, yLine+20, '{r}']
    ];
    for(const [x,y,lab] of Fpts){
      svg.appendChild(SVG('rect',{x:x-35,y:y-12,width:70,height:24,rx:6,ry:6,
        fill:'rgba(131,193,103,0.15)',stroke:'var(--green)'}));
      const t=SVG('text',{x,y:y+4,'text-anchor':'middle','font-size':12,fill:'var(--ink)','font-weight':600});
      t.textContent=lab; svg.appendChild(t);
    }
    // dashed arrows from A to F(A)
    drawArrow(svg,[76,yLine-30],[320,yLine-40],{color:'var(--green)',markerId:'kan-f',pad1:6,pad2:12,width:1,dash:'4 3'});
    drawArrow(svg,[76,yLine+30],[320,yLine+20],{color:'var(--green)',markerId:'kan-f2',pad1:6,pad2:12,width:1,dash:'4 3'});

    // Extension: assign each b ∈ B a set
    const EXT = {};
    if(mode==='lan'){
      EXT[0]='{p,q}'; EXT[1]='{p,q}'; EXT[2]='{p,q,r}';
    } else {
      EXT[0]='{p,q}×{r}'; EXT[1]='{r}'; EXT[2]='{r}';
    }
    const Etitle=SVG('text',{x:540,y:yLine-100,'font-size':13,fill:'var(--mute)','font-weight':600});
    Etitle.textContent = (mode==='lan'?'Lan_K F':'Ran_K F') + ' : B → Set';
    svg.appendChild(Etitle);
    const Epts = [
      [540, yLine-60, EXT[0]],
      [540, yLine    , EXT[1]],
      [540, yLine+60, EXT[2]]
    ];
    for(const [x,y,lab] of Epts){
      const w = Math.max(60, 10*lab.length);
      svg.appendChild(SVG('rect',{x:x-w/2,y:y-12,width:w,height:24,rx:6,ry:6,
        fill:'rgba(255,216,102,0.12)',stroke:'var(--yellow)'}));
      const t=SVG('text',{x,y:y+4,'text-anchor':'middle','font-size':12,fill:'var(--ink)','font-weight':600});
      t.textContent=lab; svg.appendChild(t);
    }
    // dashed arrows from B to extension
    drawArrow(svg,[216,yLine-60],[500,yLine-60],{color:'var(--yellow)',markerId:'kan-e1',pad1:6,pad2:20,width:1,dash:'4 3'});
    drawArrow(svg,[216,yLine],[500,yLine],{color:'var(--yellow)',markerId:'kan-e2',pad1:6,pad2:20,width:1,dash:'4 3'});
    drawArrow(svg,[216,yLine+60],[500,yLine+60],{color:'var(--yellow)',markerId:'kan-e3',pad1:6,pad2:20,width:1,dash:'4 3'});

    // readout
    let msg = '';
    if(mode==='lan'){
      msg = `A = discrete {0,1};  B = 0→M→2;  K : 0↦0, 1↦2;  F(0)={p,q}, F(1)={r}.\n\n`;
      msg += `Left Kan extension Lan_K F at each b ∈ B is the COLIMIT over (K ↓ b):\n`;
      msg += `   b=0: only (0,id), colim = F(0) = {p,q}\n`;
      msg += `   b=M: (K↓M) = {(0,0→M)}, colim = F(0) = {p,q}\n`;
      msg += `   b=2: (K↓2) = {(0,0→2),(1,id)}, colim = F(0) ⊔ F(1) = {p,q,r}\n\n`;
      msg += `universal property: for any G : B → Set and η : F ⇒ G∘K, ∃! α : Lan_K F ⇒ G extending η.`;
    } else {
      msg = `A = discrete {0,1};  B = 0→M→2;  K : 0↦0, 1↦2;  F(0)={p,q}, F(1)={r}.\n\n`;
      msg += `Right Kan extension Ran_K F at each b ∈ B is the LIMIT over (b ↓ K):\n`;
      msg += `   b=0: (0↓K) = {(0,id),(1,0→2)}, lim = F(0) × F(1) (size 2×1=2)\n`;
      msg += `   b=M: (M↓K) = {(1,M→2)}, lim = F(1) = {r}\n`;
      msg += `   b=2: (2↓K) = {(1,id)}, lim = F(1) = {r}\n\n`;
      msg += `universal property: for any G : B → Set and η : G∘K ⇒ F, ∃! α : G ⇒ Ran_K F co-extending η.`;
    }
    out.textContent = msg;
  }
  modeSel.addEventListener('change', render);
  render();
})();

