    drawArrow(svg,[140,150],[480,150],{color:'var(--ink)',markerId:'tc-h',curve:60,label:'h',width:1.4,pad1:24,pad2:26});
    // 2-cells α, β as double arrows
    function doubleArrow(x,y1,y2,color,label){
      ensureArrow(svg,'tc-2a-'+color.replace(/[^a-z]/gi,''),color);
      svg.appendChild(SVG('line',{x1:x-4,y1,x2:x-4,y2,stroke:color,'stroke-width':1.8,
        'marker-end':`url(#tc-2a-${color.replace(/[^a-z]/gi,'')})`}));
      svg.appendChild(SVG('line',{x1:x+4,y1,x2:x+4,y2,stroke:color,'stroke-width':1.8,
        'marker-end':`url(#tc-2a-${color.replace(/[^a-z]/gi,'')})`}));
      const t=SVG('text',{x:x+14,y:(y1+y2)/2+4,'font-size':13,fill:color,'font-style':'italic','font-weight':600});
      t.textContent=label; svg.appendChild(t);
    }
    doubleArrow(310, 105, 143,'var(--yellow)','α : f ⇒ g');
    if(mode==='base') doubleArrow(310, 159, 197,'var(--pink)','β : g ⇒ h');
    else {
      // Replace with composite β·α
      doubleArrow(310, 105, 197,'var(--green)','β·α : f ⇒ h');
    }
    out.textContent = mode==='base'
      ? 'Two 2-cells α : f ⇒ g and β : g ⇒ h between parallel functors A → B.\nVertical composition stacks them into β·α : f ⇒ h.'
      : 'Vertical composition β·α : f ⇒ h. Its components are (β·α)_A = β_A ∘ α_A at each object A.';
  } else if(mode==='horizontal'){
    // Three objects A, B, C. Two 2-cells α : f⇒g on A→B, α' : f'⇒g' on B→C. Horizontal α*α' : f'f ⇒ g'g.
    drawNode(svg, 100, 150, 'A', {r:22, stroke:'var(--blue)'});
    drawNode(svg, 320, 150, 'B', {r:22, stroke:'var(--blue)'});
    drawNode(svg, 540, 150, 'C', {r:22, stroke:'var(--blue)'});
    drawArrow(svg,[100,150],[320,150],{color:'var(--ink)',markerId:'tc-f1',curve:-30,label:'f',width:1.4,pad1:24,pad2:26});
    drawArrow(svg,[100,150],[320,150],{color:'var(--ink)',markerId:'tc-g1',curve:30,label:'g',width:1.4,pad1:24,pad2:26});
    drawArrow(svg,[320,150],[540,150],{color:'var(--ink)',markerId:'tc-f2',curve:-30,label:"f'",width:1.4,pad1:24,pad2:26});
    drawArrow(svg,[320,150],[540,150],{color:'var(--ink)',markerId:'tc-g2',curve:30,label:"g'",width:1.4,pad1:24,pad2:26});
    // double arrows α, α'
    function doubleArrow(x,y1,y2,color,label){
      ensureArrow(svg,'tc-d-'+color.replace(/[^a-z]/gi,''),color);
      svg.appendChild(SVG('line',{x1:x-4,y1,x2:x-4,y2,stroke:color,'stroke-width':1.8,
        'marker-end':`url(#tc-d-${color.replace(/[^a-z]/gi,'')})`}));
      svg.appendChild(SVG('line',{x1:x+4,y1,x2:x+4,y2,stroke:color,'stroke-width':1.8,
        'marker-end':`url(#tc-d-${color.replace(/[^a-z]/gi,'')})`}));
      const t=SVG('text',{x:x+14,y:(y1+y2)/2+4,'font-size':12,fill:color,'font-style':'italic','font-weight':600});
      t.textContent=label; svg.appendChild(t);
    }
    doubleArrow(210, 125, 175,'var(--yellow)','α');
    doubleArrow(430, 125, 175,'var(--pink)',"α'");
    out.textContent = `Horizontal composition α * α' : f'f ⇒ g'g, defined component-wise as (α * α')_A = g'(α_A) ∘ α'_{f(A)} = α'_{g(A)} ∘ f'(α_A).\nThe interchange law says these two orderings agree.`;
  }
}
vertBtn.addEventListener('click', ()=>{ mode='vertical'; render(); });
horizBtn.addEventListener('click',()=>{ mode='horizontal'; render(); });
resetBtn.addEventListener('click', ()=>{ mode='base'; render(); });
render();

const svg=$('#enr-svg'), out=$('#enr-out');
if(!svg) return;
// Three draggable points A, B, C in the plane; d is Euclidean. Display d(*,*) and check triangle inequality.
let pts = [
  { label:'A', x: 180, y: 110 },
  { label:'B', x: 460, y: 140 },
  { label:'C', x: 300, y: 280 }
];
let dragging = null;

function dist(p,q){ return Math.hypot(p.x-q.x, p.y-q.y); }
function render(){
  svg.innerHTML='';
  // draw triangle edges and labels
  for(let i=0;i<3;i++){
    for(let j=i+1;j<3;j++){
      const a=pts[i], b=pts[j];
      svg.appendChild(SVG('line',{x1:a.x,y1:a.y,x2:b.x,y2:b.y,
        stroke:'var(--cyan)','stroke-width':1.4,opacity:0.7}));
      const mx=(a.x+b.x)/2, my=(a.y+b.y)/2;
      const t=SVG('text',{x:mx,y:my-6,'text-anchor':'middle','font-size':11,fill:'var(--cyan)','font-family':'ui-monospace, monospace'});
      t.textContent=`d(${a.label},${b.label})=${dist(a,b).toFixed(1)}`;
      svg.appendChild(t);
    }
  }
  // draw nodes
  for(const p of pts){
    const c=SVG('circle',{cx:p.x,cy:p.y,r:14,fill:'var(--panel2)',stroke:'var(--violet)','stroke-width':2,
      style:'cursor:grab','data-node':p.label});
    svg.appendChild(c);
    const t=SVG('text',{x:p.x,y:p.y+5,'text-anchor':'middle','font-size':13,fill:'#fff','font-weight':700,'pointer-events':'none'});
    t.textContent=p.label; svg.appendChild(t);
  }

  // readout: triangle inequality checks
  const A=pts[0],B=pts[1],C=pts[2];
  const dAB=dist(A,B), dBC=dist(B,C), dAC=dist(A,C);
  let msg = `Lawvere enrichment of 3-point space {A,B,C}:\n`;
  msg += `   d(A,B) = ${dAB.toFixed(3)}\n`;
  msg += `   d(B,C) = ${dBC.toFixed(3)}\n`;
  msg += `   d(A,C) = ${dAC.toFixed(3)}\n\n`;
  msg += `enriched-composition axiom = triangle inequality.\n`;
  function check(x,y,z,dxy,dyz,dxz){
    const ok = dxy + dyz >= dxz - 1e-6;
    return `   d(${x},${y}) + d(${y},${z}) = ${(dxy+dyz).toFixed(3)}  ${ok?'≥':'<'}  d(${x},${z}) = ${dxz.toFixed(3)}   ${ok?'✓':'✗'}`;
  }
  msg += check('A','B','C',dAB,dBC,dAC) + '\n';
  msg += check('A','C','B',dAC,dBC,dAB) + '\n';
  msg += check('B','A','C',dAB,dAC,dBC) + '\n\n';
  msg += `identity axiom: d(X,X) = 0 for every X (trivially).\n\n`;
  msg += `"composition" in the enriched category is the Minkowski inequality; "identity" is  0 ≥ d(X,X).`;
  out.textContent = msg;
}

svg.addEventListener('pointerdown', e=>{
  const n = e.target && e.target.getAttribute && e.target.getAttribute('data-node');
  if(n){ dragging = pts.find(p=>p.label===n); svg.setPointerCapture(e.pointerId); }
});
svg.addEventListener('pointermove', e=>{
  if(!dragging) return;
  const pt = svg.getBoundingClientRect();
  // map pointer to viewBox coords
  const vb = svg.viewBox.baseVal;
  const x = (e.clientX - pt.left) / pt.width * vb.width;
  const y = (e.clientY - pt.top) / pt.height * vb.height;
  dragging.x = Math.max(30, Math.min(vb.width-30, x));
  dragging.y = Math.max(30, Math.min(vb.height-30, y));
  render();
});
svg.addEventListener('pointerup', e=>{ dragging=null; });
svg.addEventListener('pointercancel', e=>{ dragging=null; });
render();

